// Get all items from the previous node
const allItems = $input.all();

// This will hold our aggregated data, one entry per query
const queryData = {};

// This will hold the grand totals
const summary = {
  total_clicks_a: 0,
  total_clicks_b: 0,
  total_impr_a: 0,
  total_impr_b: 0
};

// ---
// STEP 1: Aggregate all the daily data into query-level totals
// ---
for (const item of allItems) {
  const row = item.json;
  const query = row.query;

  // Skip any rows that are missing a query
  if (!query) continue;

  // ---
  // 1a. Add to the grand total summary
  // ---
  summary.total_clicks_a += row.clicks_a || 0;
  summary.total_clicks_b += row.clicks_b || 0;
  summary.total_impr_a += row.impr_a || 0;
  summary.total_impr_b += row.impr_b || 0;

  // ---
  // 1b. Initialize the dictionary for this query if it's the first time we've seen it
  // ---
  if (!queryData[query]) {
    queryData[query] = {
      query: query,
      total_clicks_a: 0,
      total_clicks_b: 0,
      total_impr_a: 0,
      total_impr_b: 0,
      impr_pos_a_sum: 0.0, // Helper for weighted average
      impr_pos_b_sum: 0.0, // Helper for weighted average
      pages: new Set() // A set to store all unique pages for this query
    };
  }

  // ---
  // 1c. Add this row's data to the query's aggregate
  // ---
  const qEntry = queryData[query];
  qEntry.total_clicks_a += row.clicks_a || 0;
  qEntry.total_clicks_b += row.clicks_b || 0;
  qEntry.total_impr_a += row.impr_a || 0;
  qEntry.total_impr_b += row.impr_b || 0;
  qEntry.pages.add(row.page);

  // Calculate weighted average position. (pos * impressions)
  // This is more accurate than averaging averages.
  const pos_a = row.pos_a || 0;
  const impr_a = row.impr_a || 0;
  if (pos_a > 0 && impr_a > 0) {
    qEntry.impr_pos_a_sum += pos_a * impr_a;
  }

  const pos_b = row.pos_b || 0;
  const impr_b = row.impr_b || 0;
  if (pos_b > 0 && impr_b > 0) {
    qEntry.impr_pos_b_sum += pos_b * impr_b;
  }
}

// ---
// STEP 2: Calculate final averages and categorize each query
// ---
const finalResults = {
  summary: summary,
  new_keywords: [],
  lost_keywords: [],
  rising_keywords: [],
  declining_keywords: [],
  page_two_opportunities: []
};

// Define thresholds for "big" changes
const IMPRESSION_THRESHOLD = 10; // Must gain/lose at least 10 impressions
const POSITION_THRESHOLD = 1.0; // Must move at least 1 position

for (const [query, data] of Object.entries(queryData)) {

  // Calculate final weighted average positions
  let avg_pos_a = 0.0;
  if (data.total_impr_a > 0) {
    avg_pos_a = data.impr_pos_a_sum / data.total_impr_a;
  }

  let avg_pos_b = 0.0;
  if (data.total_impr_b > 0) {
    avg_pos_b = data.impr_pos_b_sum / data.total_impr_b;
  }

  // Add final calculated fields
  data.avg_pos_a = Math.round(avg_pos_a * 100) / 100;
  data.avg_pos_b = Math.round(avg_pos_b * 100) / 100;
  data.impr_diff = data.total_impr_a - data.total_impr_b;
  data.clicks_diff = data.total_clicks_a - data.total_clicks_b;

  // Calculate position difference only if both periods have data
  data.pos_diff = 0.0;
  if (avg_pos_a > 0 && avg_pos_b > 0) {
    data.pos_diff = Math.round((avg_pos_a - avg_pos_b) * 100) / 100;
  }

  // Convert set to array for proper JSON output
  data.pages = Array.from(data.pages);

  // Clean up the helper fields we don't need anymore
  delete data.impr_pos_a_sum;
  delete data.impr_pos_b_sum;

  // ---
  // 2b. Categorize the query
  // ---

  // New Keywords (had 0 impressions, now has impressions)
  if (data.total_impr_b === 0 && data.total_impr_a > 0) {
    finalResults.new_keywords.push(data);
  }
  // Lost Keywords (had impressions, now has 0)
  else if (data.total_impr_a === 0 && data.total_impr_b > 0) {
    finalResults.lost_keywords.push(data);
  }
  // Existing Keywords (had impressions in both periods)
  else if (data.total_impr_a > 0 && data.total_impr_b > 0) {

    // Rising Keywords (gained impressions AND improved ranking)
    if (data.impr_diff > IMPRESSION_THRESHOLD && data.pos_diff < -POSITION_THRESHOLD) {
      finalResults.rising_keywords.push(data);
    }

    // Declining Keywords (lost impressions AND dropped ranking)
    if (data.impr_diff < -IMPRESSION_THRESHOLD && data.pos_diff > POSITION_THRESHOLD) {
      finalResults.declining_keywords.push(data);
    }

    // Page Two Opportunities (Ranking on page 2: pos 10.1 to 20)
    // These are your best opportunities to optimize.
    if (data.avg_pos_a > 10 && data.avg_pos_a <= 20) {
      finalResults.page_two_opportunities.push(data);
    }
  }
}

// ---
// STEP 3: Sort the lists to show most important items first
// ---
finalResults.new_keywords.sort((a, b) => b.total_impr_a - a.total_impr_a);
finalResults.lost_keywords.sort((a, b) => b.total_impr_b - a.total_impr_b);
finalResults.rising_keywords.sort((a, b) => b.impr_diff - a.impr_diff);
finalResults.declining_keywords.sort((a, b) => a.impr_diff - b.impr_diff);
finalResults.page_two_opportunities.sort((a, b) => b.total_impr_a - a.total_impr_a);

// Add counts to the summary
summary.new_keyword_count = finalResults.new_keywords.length;
summary.lost_keyword_count = finalResults.lost_keywords.length;
summary.rising_keyword_count = finalResults.rising_keywords.length;
summary.declining_keyword_count = finalResults.declining_keywords.length;
summary.page_two_opportunities_count = finalResults.page_two_opportunities.length;

// Add date ranges from the first item (assuming they're all the same)
if (allItems.length > 0) {
  summary.range_a = allItems[0].json.range_a;
  summary.range_b = allItems[0].json.range_b;
}

// ---
// STEP 4: Return the single JSON object to n8n
// ---
return [finalResults];

// 1. Get the text output from Gemini Agent
const text = $input.item.json.output;

// 2. Use Regex to find the content inside ```json ... ```
const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/);

// 3. If found, parse it into real JSON data
if (jsonMatch && jsonMatch[1]) {
  const cleanData = JSON.parse(jsonMatch[1]);
  return cleanData; // Returns the array of 5 topics directly
} else {
  // Fallback: If AI didn't use markdown, try to return as is or log error
  return { "raw_text": text, "error": "No JSON block found" };
}
